/// <summary>
/// Extension class of <c>SalesConfirmDP</c> for text block management
/// </summary>
[ExtensionOf(classStr(SalesConfirmDP))]
final class FWFTextBlockSalesConfirmDP_Extension
{
}

Method.Source:
protected SalesConfirmHeaderTmp initializeSalesOrderConfirmationHeader()
{
    SalesConfirmHeaderTmp salesConfirmHeaderTmpCreated = next initializeSalesOrderConfirmationHeader();

    FWFTextBlockReportTextInit::newParameters(salesConfirmHeaderTmpCreated, this.parmCustConfirmJour()).addTexts();

    return salesConfirmHeaderTmpCreated;
}

protected SalesConfirmDetailsTmp initializeSalesOrderConfirmationLine(SalesConfirmHeaderTmp _salesConfirmHeaderTmp, SalesConfirmDPConfirmationLineQuerySelection _confirmationLineSelection)
{
    SalesConfirmDetailsTmp salesConfirmDetailsTmpCreated = next initializeSalesOrderConfirmationLine(_salesConfirmHeaderTmp, _confirmationLineSelection);

    FWFTextBlockReportTextInit::newParameters(salesConfirmDetailsTmpCreated, _confirmationLineSelection.parmCustConfirmTrans()).addTexts();

    return salesConfirmDetailsTmpCreated;
}
